#include <assert.h>
#include <string.h>
#include <stdio.h>
#include "jv.h"

void test_jv_string(void) {
    jv s = jv_string("hello");
    assert(jv_get_kind(s) == JV_KIND_STRING);
    assert(strcmp(jv_string_value(s), "hello") == 0);
    jv_free(s);
}

void test_jv_number(void) {
    jv n = jv_number(42.0);
    assert(jv_get_kind(n) == JV_KIND_NUMBER);
    assert(jv_number_value(n) == 42.0);
    jv_free(n);
}

void test_jv_object(void) {
    jv obj = jv_object();
    obj = jv_object_set(obj, jv_string("key"), jv_string("value"));
    assert(jv_get_kind(obj) == JV_KIND_OBJECT);
    jv_free(obj);
}

int main(void) {
    test_jv_string();
    test_jv_number();
    test_jv_object();
    printf("All jv tests passed!\n");
    return 0;
}
